import { CouponService, CouponError } from "./coupon-service";
import { Coupon, CouponRepository } from "./coupon-repository";

// ---------------------------------------------------------------------------
// Mock repository factory
// ---------------------------------------------------------------------------

function makeMockRepo(coupons: Record<string, Coupon>): CouponRepository {
  return {
    getCoupon(code: string): Coupon | null {
      return coupons[code] ?? null;
    },
  };
}

// ---------------------------------------------------------------------------
// Fixture coupons
// ---------------------------------------------------------------------------

const SAVE10_COUPON: Coupon = {
  code: "SAVE10",
  discountPercent: 10,
  expired: false,
  singleUse: false,
  used: false,
};

const EXPIRED_COUPON: Coupon = {
  code: "EXPIRED20",
  discountPercent: 20,
  expired: true,
  singleUse: false,
  used: false,
};

const MIN_ORDER_COUPON: Coupon = {
  code: "MIN50",
  discountPercent: 15,
  expired: false,
  minimumOrder: 50,
  singleUse: false,
  used: false,
};

const SINGLE_USE_USED_COUPON: Coupon = {
  code: "ONETIME",
  discountPercent: 5,
  expired: false,
  singleUse: true,
  used: true,
};

const SINGLE_USE_UNUSED_COUPON: Coupon = {
  code: "FIRSTUSE",
  discountPercent: 5,
  expired: false,
  singleUse: true,
  used: false,
};

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("CouponService.applyCoupon", () => {
  const repo = makeMockRepo({
    [SAVE10_COUPON.code]: SAVE10_COUPON,
    [EXPIRED_COUPON.code]: EXPIRED_COUPON,
    [MIN_ORDER_COUPON.code]: MIN_ORDER_COUPON,
    [SINGLE_USE_USED_COUPON.code]: SINGLE_USE_USED_COUPON,
    [SINGLE_USE_UNUSED_COUPON.code]: SINGLE_USE_UNUSED_COUPON,
  });
  const service = new CouponService(repo);

  // -------------------------------------------------------------------------
  // Acceptance criteria — verbatim from spec
  // -------------------------------------------------------------------------

  it("AC1: valid SAVE10 applies 10% off — cartTotal * 0.90", () => {
    expect(service.applyCoupon(100, "SAVE10")).toBe(90);
  });

  it("AC2: expired coupon throws CouponError with code COUPON_EXPIRED", () => {
    expect(() => service.applyCoupon(100, "EXPIRED20")).toThrow(CouponError);
    expect(() => service.applyCoupon(100, "EXPIRED20")).toThrow(
      expect.objectContaining({ code: "COUPON_EXPIRED" })
    );
  });

  it("AC3: unknown coupon code throws CouponError with code COUPON_NOT_FOUND", () => {
    expect(() => service.applyCoupon(100, "DOESNOTEXIST")).toThrow(CouponError);
    expect(() => service.applyCoupon(100, "DOESNOTEXIST")).toThrow(
      expect.objectContaining({ code: "COUPON_NOT_FOUND" })
    );
  });

  it("AC4: cartTotal $40 below minimumOrder $50 throws CouponError with code ORDER_MINIMUM_NOT_MET", () => {
    expect(() => service.applyCoupon(40, "MIN50")).toThrow(CouponError);
    expect(() => service.applyCoupon(40, "MIN50")).toThrow(
      expect.objectContaining({ code: "ORDER_MINIMUM_NOT_MET" })
    );
  });

  it("AC5: single-use coupon already used throws CouponError with code COUPON_ALREADY_USED", () => {
    expect(() => service.applyCoupon(100, "ONETIME")).toThrow(CouponError);
    expect(() => service.applyCoupon(100, "ONETIME")).toThrow(
      expect.objectContaining({ code: "COUPON_ALREADY_USED" })
    );
  });

  // -------------------------------------------------------------------------
  // Edge cases
  // -------------------------------------------------------------------------

  it("AC1 (fractional): SAVE10 on $55.50 → $49.95", () => {
    expect(service.applyCoupon(55.5, "SAVE10")).toBeCloseTo(49.95);
  });

  it("AC4 (boundary): cartTotal exactly at minimumOrder ($50) should succeed and apply discount", () => {
    expect(service.applyCoupon(50, "MIN50")).toBeCloseTo(42.5);
  });

  it("AC5 (inverse): single-use coupon not yet used succeeds", () => {
    expect(service.applyCoupon(100, "FIRSTUSE")).toBe(95);
  });

  it("non-single-use coupon with used=true still applies (used flag only matters for singleUse coupons)", () => {
    const repo = makeMockRepo({
      MULTI: {
        code: "MULTI",
        discountPercent: 10,
        expired: false,
        singleUse: false,
        used: true, // used=true but singleUse=false → should still work
      },
    });
    const svc = new CouponService(repo);
    expect(svc.applyCoupon(100, "MULTI")).toBe(90);
  });
});

